from kafka import KafkaConsumer
import json

# Define a dictionary to hold message handlers
message_handlers = {}

def register_handler(topic, handler):
    if topic in message_handlers:
        raise ValueError(f"Handler already registered for topic: {topic}")
    message_handlers[topic] = handler

def process_message(message):
    topic = message.topic
    value = json.loads(message.value)
    
    if topic in message_handlers:
        handler = message_handlers[topic]
        handler(value)
    else:
        print(f"No handler registered for topic: {topic}")

# Example handler function
def handle_financial_transaction(transaction):
    # Business logic to process financial transaction
    print(f"Processing transaction: {transaction}")

# Register the handler for a specific topic
register_handler('financial_transactions', handle_financial_transaction)

# Create Kafka consumer
consumer = KafkaConsumer(
    'financial_transactions',
    bootstrap_servers=['localhost:9092'],
    auto_offset_reset='earliest',
    enable_auto_commit=True,
    group_id='financial_transaction_group',
    value_deserializer=lambda x: json.loads(x.decode('utf-8'))
)

# Consume messages
for message in consumer:
    process_message(message)